      "利群": params.IMG8,
      "南京": params.IMG9,
      "泰山": params.IMG10,
      "云烟": params.IMG11,
      "七匹狼":params.IMG12,
      "大前门":params.IMG13,

      "七星":params.IMG15,
      "双喜":params.IMG16,
      "中南海":params.IMG17,
      "黄金叶":params.IMG18,
      "兰州":params.IMG19,
    };

    const imageUrls = brandList
    .filter((name): name is string => typeof name === "string")
    .map(name => name.trim())
    .map(name => cigaretteMap[name])
    .filter((url): url is string => Boolean(url));

  return {
    outputs: imageUrls,
    theme_url: (typeof params.zhuti === "string" && cigaretteMap[params.zhuti.trim()]) || imageUrls[2] || imageUrls[0] || ""
  };
}

import re


async def main(args: Args) -> Output:
    params = getattr(args, "params", None) or {}
    items = params.get("data") or []
    strip_chars = "\u201c\u201d\u2018\u2019\"'\u300a\u300b\u3008\u3009\u3010\u3011()\uff08\uff09\u2026\u2014\uff1a:\uff1b;"
    cleaned = []
    for it in items:
        s = str(it or "").strip()
        for ch in strip_chars:
            s = s.replace(ch, "")
        s = s.strip()
        if s and re.search(r"[\u4e00-\u9fff0-9A-Za-z]", s):
            cleaned.append(s)
    return {"data": cleaned}

